@startuml
title CASSANDRA's Class Diagram

skinparam packageStyle rectangle
skinparam shadowing false
skinparam classAttributeIconSize 0

package "it" {
  package "unipi" {
    package "lsmsdb" {
      package "stocksim" {
        package "lib" {
          package "database" {

            interface DBFactory
            interface DB

            package "cassandra" {

              class CQLSessionException {
                +CQLSessionException()
              }

              class CassandraDBFactory {
                +create()
                +getCassandraDB()
                -CassandraDBFactory()
              }

              class CassandraDB {
                -contactPoints : Vector<InetSocketAddress>
                -cqlSession : CqlSession
                -datacenter : String
                -hostnames : ArrayList<String>
                -ports : ArrayList<Integer>
                --
                +connect()
                +disconnect()
                +execute()
                +prepareStatement()
                +query()
                +query()
                #CassandraDB()
              }

              class Main {
                +main()
                +testAggregation()
              }
            }

            CassandraDBFactory ..|> DBFactory
            CassandraDB ..|> DB
          }
        }
      }
    }
  }
}
@enduml
